import{_ as i,o as a,c as e,a2 as o}from"./chunks/framework.VshInwhI.js";const p=JSON.parse('{"title":"详情页 UI 规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/09-detail-page.md","filePath":"mango-pmo/rules/frontend/09-detail-page.md"}'),t={name:"mango-pmo/rules/frontend/09-detail-page.md"};function r(n,l,d,s,h,_){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="详情页-ui-规范" tabindex="-1">详情页 UI 规范 <a class="header-anchor" href="#详情页-ui-规范" aria-label="Permalink to &quot;详情页 UI 规范&quot;">​</a></h1><h2 id="_1-页面结构" tabindex="-1">1. 页面结构 <a class="header-anchor" href="#_1-页面结构" aria-label="Permalink to &quot;1. 页面结构&quot;">​</a></h2><ol><li>详情页是下级页面，必须有返回栏。</li><li>返回栏只放返回图标和当前标题。</li><li>返回栏不放面包屑、状态、页面操作按钮。</li><li>页面级操作放到底部悬浮操作栏。</li><li>底部操作栏与内容区同宽，按钮居中展示。</li></ol><h2 id="_2-业务组织" tabindex="-1">2. 业务组织 <a class="header-anchor" href="#_2-业务组织" aria-label="Permalink to &quot;2. 业务组织&quot;">​</a></h2><p>详情展示必须按业务判断路径组织，不能按接口字段、数据库字段顺序展开。</p><p>推荐顺序：</p><ol><li>识别信息：当前对象是谁。</li><li>状态与金额：当前状态、关键金额、数量、余额、结果。</li><li>通道、账户、关联对象：和业务判断相关的外部对象。</li><li>凭证与结果：附件、依据、处理结果、失败原因。</li><li>时间与审计：谁在什么时候做了什么。</li></ol><h2 id="_3-模块与字段" tabindex="-1">3. 模块与字段 <a class="header-anchor" href="#_3-模块与字段" aria-label="Permalink to &quot;3. 模块与字段&quot;">​</a></h2><ol><li>详情页必须按业务模块分组。</li><li>模块标题必须清晰，例如基本信息、金额信息、账户信息、凭证与结果、时间与审计。</li><li>字段展示优先使用 <code>ElDescriptions</code>。</li><li>后面的字段要能参考前面的字段。</li><li>有对比、级联、依赖、计算关系的字段必须相邻。</li><li>长文本字段单独占整行。</li><li>关联数据较多时使用模块内表格。</li><li>技术字段后置、折叠或放入独立技术信息分组。</li></ol><h2 id="_4-技术字段" tabindex="-1">4. 技术字段 <a class="header-anchor" href="#_4-技术字段" aria-label="Permalink to &quot;4. 技术字段&quot;">​</a></h2><p>以下字段不得放在主业务阅读路径前面：</p><ul><li>内部 ID</li><li>规则 ID</li><li>JSON</li><li>扩展参数</li><li>报文</li><li>trace 信息</li><li>低频审计信息</li></ul><h2 id="_5-检查清单" tabindex="-1">5. 检查清单 <a class="header-anchor" href="#_5-检查清单" aria-label="Permalink to &quot;5. 检查清单&quot;">​</a></h2><ol><li>是否按业务判断路径组织。</li><li>每个模块标题是否能说明字段归属。</li><li>字段顺序是否符合业务先后。</li><li>对比、级联、计算字段是否相邻。</li><li>技术字段是否后置。</li><li>状态是否放在概要模块或具体字段中，而不是返回栏。</li><li>是否覆盖 loading、empty、error 和无权限状态。</li></ol>',14)])])}const u=i(t,[["render",r]]);export{p as __pageData,u as default};
